                       >\r\n                                <el-option\r\n                                    v-for=\"(label, key) in columns\"\r\n                                    :key=\"key\"\r\n                                    :value=\"key\"\r\n                                    :label=\"label\"\r\n                                ></el-option>\r\n                            </el-select>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-lg-3 col-md-4 col-sm-12 pb-2\">\r\n                        <template\r\n                            v-if=\"\r\n                                search.column == 'date_of_issue' ||\r\n                                    search.column == 'date_of_due' ||\r\n                                    search.column == 'date_of_payment' ||\r\n                                    search.column == 'delivery_date' ||\r\n                                    search.column == 'date'\r\n                            \"\r\n                        >\r\n                            <template\r\n                                v-if=\"resource != 'restaurant/worker/expenses'\"\r\n                            >\r\n                                <el-date-picker\r\n                                    v-model=\"search.value\"\r\n                                    type=\"date\"\r\n                                    style=\"width: 100%;\"\r\n                                    placeholder=\"Buscar\"\r\n                                    value-format=\"yyyy-MM-dd\"\r\n                                    @change=\"getRecords\"\r\n                                >\r\n                                </el-date-picker>\r\n                            </template>\r\n                            <template v-else>\r\n                                <el-date-picker\r\n                                    v-model=\"search.value\"\r\n                                    type=\"daterange\"\r\n                                    range-separator=\"A\"\r\n                                    start-placeholder=\"Desde\"\r\n                                    value-format=\"yyyy-MM-dd\"\r\n                                    end-placeholder=\"Hasta\"\r\n                                    @change=\"getRecords\"\r\n                                >\r\n                                </el-date-picker>\r\n                            </template>\r\n                        </template>\r\n                        <template v-else-if=\"search.column == 'district_id'\">\r\n                            <el-select\r\n                                v-model=\"search.value\"\r\n                                @change=\"getRecords\"\r\n                                placeholder=\"Seleccione el Distrito\"\r\n                            >\r\n                                <el-option\r\n                                    v-for=\"item in array_district\"\r\n                                    :key=\"item.id\"\r\n                                    :label=\"item.description\"\r\n                                    :value=\"item.id\"\r\n                                >\r\n                                </el-option>\r\n                            </el-select>\r\n                        </template>\r\n                        <template v-else>\r\n                            <el-input\r\n                                placeholder=\"Buscar\"\r\n                                v-model=\"search.value\"\r\n                                style=\"width: 100%;\"\r\n                                prefix-icon=\"el-icon-search\"\r\n                                @input=\"getRecords\"\r\n                            >\r\n                            </el-input>\r\n                        </template>\r\n                    </div>\r\n                </div>\r\n            </div>\r\n            <div\r\n                v-if=\"\r\n                    resource == 'restaurant/worker/expenses' &&\r\n                        records.length != 0\r\n                \"\r\n                class=\"row\"\r\n            >\r\n                <div class=\"col-md-3\">\r\n                    <el-button\r\n                        class=\"submit\"\r\n                        type=\"danger\"\r\n                        icon=\"el-icon-tickets\"\r\n                        @click.prevent=\"clickDownload('pdf')\"\r\n                        >Exportar PDF</el-button\r\n                    >\r\n                </div>\r\n            </div>\r\n            <div class=\"col-md-12\">\r\n                <div class=\"table-responsive\">\r\n                    <table class=\"table\">\r\n                        <thead>\r\n                            <slot name=\"heading\"></slot>\r\n                        </thead>\r\n                        <tbody>\r\n                            <slot\r\n                                v-for=\"(row, index) in records\"\r\n                                :row=\"row\"\r\n                                :index=\"customIndex(index)\"\r\n                            ></slot>\r\n                        </tbody>\r\n                    </table>\r\n                    <div>\r\n                        <el-pagination\r\n                            @current-change=\"getRecords\"\r\n                            layout=\"total, prev, pager, next\"\r\n                            :total=\"pagination.total\"\r\n                            :current-page.sync=\"pagination.current_page\"\r\n                            :page-size=\"pagination.per_page\"\r\n                        >\r\n                        </el-pagination>\r\n                    </div>\r\n                </div>\r\n            </div>\r\n        </div>\r\n    </div>\r\n</template>\r\n\r\n<script>\r\nimport moment from \"moment\";\r\nimport queryString from \"query-string\";\r\n\r\nexport default {\r\n    props: {\r\n        resource: String,\r\n        applyFilter: {\r\n            type: Boolean,\r\n            default: true,\r\n            required: false\r\n        },\r\n        fromAdmin: {\r\n            type: Boolean,\r\n            default: false,\r\n            required: false\r\n        },\r\n        config: Object\r\n    },\r\n    data() {\r\n        return {\r\n            search: {\r\n                column: null,\r\n                value: null\r\n            },\r\n            columns: [],\r\n            records: [],\r\n            pagination: {},\r\n            array_district: [],\r\n            time: null\r\n        };\r\n    },\r\n    computed: {},\r\n    created() {\r\n        this.$eventHub.$on(\"reloadData\", () => {\r\n            this.getRecords();\r\n        });\r\n    },\r\n    async mounted() {\r\n        let column_resource = this.resource; // _.split(this.resource, '/')\r\n        await this.$http.get(`/${this.resource}/columns`).then(response => {\r\n            this.columns = response.data;\r\n            this.search.column = _.head(Object.keys(this.columns));\r\n        });\r\n        await this.getRecords();\r\n    },\r\n    methods: {\r\n        clickDownload() {\r\n            this.$emit(\"clickReport\", this.search);\r\n        },\r\n\r\n        customIndex(index) {\r\n            return (\r\n                this.pagination.per_page * (this.pagination.current_page - 1) +\r\n                index +\r\n                1\r\n            );\r\n        },\r\n        getRecords() {\r\n            if (this.time) {\r\n                clearTimeout(this.time);\r\n            }\r\n            //   this.$http.get(`/filtrar_distritos/records`)\r\n            // .then(response => {\r\n            //     this.array_district = response.data.district\r\n\r\n            // })\r\n            this.time = setTimeout(async () => {\r\n                let url = `/${\r\n                    this.resource\r\n                }/records?${this.getQueryParameters()}`;\r\n                if (this.fromAdmin) {\r\n                    url = `/${\r\n                        this.resource\r\n                    }/records?${this.getQueryParameters()}&fromAdmin=true`;\r\n                }\r\n                return this.$http.get(url).then(response => {\r\n                    this.records = response.data.data;\r\n                    this.pagination = response.data.meta;\r\n                    this.pagination.per_page = parseInt(\r\n                        response.data.meta.per_page\r\n                    );\r\n                });\r\n            }, 350);\r\n        },\r\n        getQueryParameters() {\r\n            if (\r\n                this.search.column == \"date\" &&\r\n                this.search.value &&\r\n                typeof this.search.value == \"object\"\r\n            ) {\r\n                this.search.value = this.search.value.join(\",\");\r\n            }\r\n            return queryString.stringify({\r\n                page: this.pagination.current_page,\r\n                limit: this.limit,\r\n                value: this.search.value,\r\n                column: this.search.column\r\n            });\r\n        },\r\n        changeClearInput() {\r\n            this.search.value = \"\";\r\n            this.getRecords();\r\n        }\r\n    }\r\n};\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// resources/js/components/DataTable.vue","<template>\r\n    <el-dialog\r\n        v-loading=\"loading_print\"\r\n        :element-loading-text=\"message\"\r\n        :title=\"titleDialog\"\r\n        :visible=\"showDialog\"\r\n        @open=\"create\"\r\n        :close-on-click-modal=\"false\"\r\n        :close-on-press-escape=\"false\"\r\n        :show-close=\"false\"\r\n        append-to-body\r\n    >\r\n        <div class=\"row mb-4\" v-if=\"form.response_message\">\r\n            <div class=\"col-md-12\">\r\n                <el-alert\r\n                    :title=\"form.response_message\"\r\n                    :type=\"form.response_type\"\r\n                    show-icon\r\n                >\r\n                </el-alert>\r\n            </div>\r\n        </div>\r\n        <div class=\"row\">\r\n            <div\r\n                class=\"col-lg-12 col-md-12 col-sm-12 text-center font-weight-bold\"\r\n                v-if=\"!locked_emission.success\"\r\n            >\r\n                <el-alert\r\n                    :title=\"locked_emission.message\"\r\n                    type=\"warning\"\r\n                    show-icon\r\n                >\r\n                </el-alert>\r\n            </div>\r\n\r\n            <div\r\n                class=\"col-lg-3 col-md-3 col-sm-12 text-center font-weight-bold mt-3\"\r\n            >\r\n                <button\r\n                    type=\"button\"\r\n                    class=\"btn btn-lg btn-info waves-effect waves-light\"\r\n                    @click=\"clickPrint('a4')\"\r\n                >\r\n                    <i class=\"fa fa-file-alt\"></i>\r\n                </button>\r\n                <p>Imprimir A4</p>\r\n            </div>\r\n            <div\r\n                class=\"col-lg-3 col-md-3 col-sm-12 text-center font-weight-bold mt-3\"\r\n            >\r\n                <button\r\n                    type=\"button\"\r\n                    class=\"btn btn-lg btn-info waves-effect waves-light\"\r\n                    @click=\"clickPrint('a5')\"\r\n                >\r\n                    <i class=\"fa fa-receipt\"></i>\r\n                </button>\r\n                <p>Imprimir A5</p>\r\n            </div>\r\n            <div\r\n                class=\"col-lg-3 col-md-3 col-sm-12 text-center font-weight-bold mt-3\"\r\n            >\r\n                <button\r\n                    type=\"button\"\r\n                    class=\"btn btn-lg btn-info waves-effect waves-light\"\r\n                    @click=\"clickPrint('ticket')\"\r\n                >\r\n                    <i class=\"fa fa-receipt\"></i>\r\n                </button>\r\n                <p>Imprimir Ticket 80MM</p>\r\n            </div>\r\n\r\n            <div\r\n                class=\"col-lg-3 col-md-3 col-sm-12 text-center font-weight-bold mt-3\"\r\n            >\r\n                <button\r\n                    type=\"button\"\r\n                    class=\"btn btn-lg btn-info waves-effect waves-light\"\r\n                    @click=\"clickPrint('ticket_50')\"\r\n                >\r\n                    <i class=\"fa fa-receipt\"></i>\r\n                </button>\r\n                <p>Imprimir Ticket 50MM</p>\r\n            </div>\r\n\r\n            <div\r\n                class=\"col-lg-12 col-md-12 col-sm-12 text-center font-weight-bold mt-3\"\r\n                v-if=\"form.image_detraction\"\r\n            >\r\n                <a\r\n                    :href=\"`${this.form.image_detraction}`\"\r\n                    download\r\n                    class=\"text-center font-weight-bold \"\r\n                    >Descargar constancia de pago - detracción</a\r\n                >\r\n            </div>\r\n        </div>\r\n        <!-- <div class=\"row mt-4\">\r\n            <div class=\"col-lg-6 col-md-6 col-sm-12 text-center\">\r\n                <button type=\"button\" class=\"btn btn-lg waves-effect waves-light btn-outline-secondary\" @click=\"clickDownload('a4')\">\r\n                    <i class=\"fa fa-download\"></i>&nbsp;&nbsp;Descargar A4\r\n                </button>\r\n            </div>\r\n            <div class=\"col-lg-6 col-md-6 col-sm-12 text-center\">\r\n                <button type=\"button\" class=\"btn btn-lg waves-effect waves-light btn-outline-secondary\" @click=\"clickDownload('ticket')\">\r\n                    <i class=\"fa fa-download\"></i>&nbsp;&nbsp;Descargar Ticket\r\n                </button>\r\n            </div>\r\n        </div> -->\r\n        <div class=\"row mt-3\">\r\n            <div class=\"col-md-12\">\r\n                <el-input v-model=\"form.customer_email\">\r\n                    <el-button\r\n                        slot=\"append\"\r\n                        icon=\"el-icon-message\"\r\n                        @click=\"clickSendEmail\"\r\n                        :loading=\"loading\"\r\n                        >Enviar</el-button\r\n                    >\r\n                    <i slot=\"prefix\" class=\"el-icon-edit-outline\"></i\r\n                ></el-input>\r\n                <small\r\n                    class=\"form-control-feedback\"\r\n                    v-if=\"errors.customer_email\"\r\n                    v-text=\"errors.customer_email[0]\"\r\n                ></small>\r\n            </div>\r\n        </div>\r\n        <div class=\"row mt-3\">\r\n            <div class=\"col-md-12\">\r\n                <el-input v-model=\"form.customer_telephone\">\r\n                    <template slot=\"prepend\">+51</template>\r\n                    <el-button slot=\"append\" @click=\"clickSendWhatsapp\"\r\n                        >Enviar\r\n                        <el-tooltip\r\n                            class=\"item\"\r\n                            effect=\"dark\"\r\n                            content=\"Es necesario tener aperturado Whatsapp web\"\r\n                            placement=\"top-start\"\r\n                        >\r\n                            <i class=\"fab fa-whatsapp\"></i>\r\n                        </el-tooltip>\r\n                    </el-button>\r\n                    <i slot=\"prefix\" class=\"el-icon-edit-outline\"></i\r\n                ></el-input>\r\n                <small\r\n                    class=\"form-control-feedback\"\r\n                    v-if=\"errors.customer_telephone\"\r\n                    v-text=\"errors.customer_telephone[0]\"\r\n                ></small>\r\n            </div>\r\n        </div>\r\n        <!-- <div class=\"row m-t-10\" >\r\n            <div class=\"col-md-12 text-center\">\r\n                <button type=\"button\" class=\"btn waves-effect waves-light btn-outline-primary\"\r\n                        @click.prevent=\"clickConsultCdr(form.id)\">Consultar CDR</button>\r\n            </div>\r\n        </div> -->\r\n        <span slot=\"footer\" class=\"dialog-footer\">\r\n            <template v-if=\"showClose\">\r\n                <el-button @click=\"clickClose\">Cerrar</el-button>\r\n            </template>\r\n            <template v-else>\r\n                <el-button class=\"list\" @click=\"clickFinalize\"\r\n                    >Ir al listado</el-button\r\n                >\r\n                <el-button type=\"primary\" @click=\"clickNewDocument\"\r\n                    >Nuevo comprobante</el-button\r\n                >\r\n            </template>\r\n        </span>\r\n    </el-dialog>\r\n</template>\r\n\r\n<script>\r\nexport default {\r\n    props: [\r\n        \"company\",\r\n        \"showDialog\",\r\n        \"recordId\",\r\n        \"configuration\",\r\n        \"showClose\",\r\n        \"isContingency\",\r\n        \"generatDispatch\",\r\n        \"dispatchId\",\r\n        \"editDocument\",\r\n        \"print\"\r\n    ],\r\n    data() {\r\n        return {\r\n            titleDialog: null,\r\n            loading: false,\r\n            resource: \"documents\",\r\n            errors: {},\r\n            form: {},\r\n            // company: {},\r\n            locked_emission: {},\r\n            loading_print: false,\r\n            message: \"\",\r\n            sender: null\r\n        };\r\n    },\r\n    async created() {\r\n        console.log(this.company);\r\n        this.initForm();\r\n        this.socketWhatsappConfig();\r\n        // await this.$http.get(`/companies/record`).then(response => {\r\n        //     if (response.data !== \"\") {\r\n        //         this.company = response.data.data;\r\n        //     }\r\n        // });\r\n    },\r\n    mounted() {},\r\n    methods: {\r\n        socketWhatsappConfig() {\r\n            let hostName = window.location.hostname;\r\n            let url = `https://${hostName}`;\r\n            this.sender = hostName\r\n                .replace(/https?\\:\\/\\//, \"\")\r\n                .replace(\"/\", \"\")\r\n                .split(\".\")\r\n                .join(\"\");\r\n            try {\r\n                this.socket = io.connect(this.$socketUrl);\r\n            } catch (e) {\r\n                console.log(e);\r\n            }\r\n            this.socket.on(\"ready\", message => {\r\n                this.showMessage(message);\r\n            });\r\n            this.socket.on(\"authenticated\", ({ message, sender }) => {\r\n                this.sender = sender;\r\n                this.showMessage(message);\r\n            });\r\n            this.socket.on(\"connected\", ({ message }) => {\r\n                this.$message.success(message);\r\n\r\n                this.socket.emit(\"getStatus\", url);\r\n            });\r\n            this.socket.on(\"setStatus\", ({ status, sender }) => {\r\n                console.log(sender);\r\n                if (!status) {\r\n                    this.sender = \"sdrimsac\";\r\n                    this.$message.warning(\"Sesión iniciada con SDRIMSAC\");\r\n                } else {\r\n                    this.sender = sender;\r\n                    this.$message.success(\"Whatsapp Listo!\");\r\n                }\r\n            });\r\n            //MessageResponse\r\n        },\r\n        async clickSendWhatsapp() {\r\n            if (this.form.customer_telephone != null) {\r\n                let formWhatsapp = {\r\n                    id: this.recordId,\r\n                    sender: this.sender,\r\n                    document_id: this.recordId,\r\n                    document_type_id: this.form.document_type_id,\r\n                    customer_telephone: this.form.customer_telephone,\r\n                    mensaje:\r\n                        \"Su comprobante de pago electrónico \" +\r\n                        this.form.number +\r\n                        \" de *\" +\r\n                        this.company.name +\r\n                        \"*, ha sido generado correctamente a través del facturador electrónico de *Sdrimsac Solutions*\"\r\n                };\r\n                try {\r\n                    this.loading = true;\r\n                    let response = await this.$http.post(\r\n                        `/whatsapp`,\r\n                        formWhatsapp\r\n                    );\r\n                    if (response.status == 200) {\r\n                        this.$toast.success(\"Mensaje enviado\");\r\n                        this.loading = false;\r\n                    }\r\n                    if (this.configuration.xml_whatsapp) {\r\n                        formWhatsapp.xml = true;\r\n                        response = await this.$http.post(\r\n                            `/whatsapp`,\r\n                            formWhatsapp\r\n                        );\r\n                        if (response.status == 200) {\r\n                            this.$toast.success(\"Mensaje enviado\");\r\n                            this.loading = false;\r\n                        }\r\n                    }\r\n                } catch (e) {\r\n                    console.log(e, \" error\");\r\n                } finally {\r\n                    this.loading = false;\r\n                }\r\n            }\r\n        },\r\n\r\n        initForm() {\r\n            this.errors = {};\r\n            this.form = {\r\n                customer_email: null,\r\n                download_pdf: null,\r\n                external_id: null,\r\n                number: null,\r\n                image_detraction: null,\r\n                id: null,\r\n                response_message: null,\r\n                response_type: null,\r\n                customer_telephone: null,\r\n                message_text: null\r\n            };\r\n            this.locked_emission = {\r\n                success: true,\r\n                message: null\r\n            };\r\n        },\r\n        async print_pdf(PrinterName, FileLink) {\r\n            try {\r\n                let config = qz.configs.create(PrinterName, {\r\n                    scaleContent: false\r\n                });\r\n                if (!qz.websocket.isActive()) {\r\n                    await qz.websocket.connect(config);\r\n                }\r\n                let data = [\r\n                    {\r\n                        type: \"pdf\",\r\n                        format: \"file\",\r\n                        data: FileLink\r\n                    }\r\n                ];\r\n                qz.print(config, data).catch(e => {\r\n                    this.$toast.error(e.message);\r\n                });\r\n            } catch (e) {\r\n                this.$toast.error(e.message);\r\n            }\r\n        },\r\n        async create() {\r\n            this.loading_print = true;\r\n            this.message = \"Cargando la información del Comprobante\";\r\n            let printer_directo = null;\r\n            let printer = null;\r\n            let formatoPdf = null;\r\n            await this.$http\r\n                .get(`/${this.resource}/record/${this.recordId}`)\r\n                .then(response => {\r\n                    this.form = response.data.data;\r\n\r\n                    this.titleDialog = \"Comprobante: \" + this.form.number;\r\n                    this.loading_print = false;\r\n                    // }\r\n                    if (this.generatDispatch)\r\n                        window.open(\r\n                            `/dispatches/create/${this.form.id}/i/${this.dispatchId}`\r\n                        );\r\n                });\r\n\r\n            await this.$http\r\n                .get(`/${this.resource}/locked_emission`)\r\n                .then(response => {\r\n                    this.locked_emission = response.data;\r\n                });\r\n        },\r\n        async clickPrintPos(printerName, formatoPdf) {\r\n            try {\r\n                this.message =\r\n                    \"Espere imprimiendo el Comprobante \" + this.form.number;\r\n                this.loading_print = true;\r\n                let config = qz.configs.create(\r\n                    printerName,\r\n                    { scaleContent: false },\r\n                    { jobName: this.form.number }\r\n                );\r\n                if (!qz.websocket.isActive()) {\r\n                    await qz.websocket.connect(config);\r\n                }\r\n                let data = [\r\n                    {\r\n                        type: \"pdf\",\r\n                        format: \"file\",\r\n                        data: formatoPdf\r\n                    }\r\n                ];\r\n                qz.print(config, data).catch(e => {\r\n                    this.$toast.error(e.message);\r\n                });\r\n\r\n                this.loading_print = false;\r\n                this.clickClose();\r\n            } catch (e) {\r\n                this.$toast.error(e.message);\r\n            }\r\n        },\r\n        clickPrint(format) {\r\n            // if(this.configuration.print_direct==1){\r\n            //     if(format==\"a4\"){\r\n            //         this.clickPrintPos(this.form.printer,this.form.print_a4)\r\n            //     }\r\n            //     if(format==\"a5\"){\r\n            //         this.clickPrintPos(this.form.printer,this.form.print_a4)\r\n            //     }\r\n            //     if(format==\"ticket\"){\r\n            //         this.clickPrintPos(this.form.printer,this.form.ticket)\r\n            //     }\r\n            //     if(format==\"ticket_50\"){\r\n            //         this.clickPrintPos(this.form.printer,this.form.ticket_50)\r\n            //     }\r\n            //     }else{\r\n            window.open(\r\n                `/print/document/${this.form.external_id}/${format}`,\r\n                \"_blank\"\r\n            );\r\n            //   }\r\n        },\r\n        clickDownloadImage() {\r\n            window.open(`${this.form.image_detraction}`, \"_blank\");\r\n        },\r\n        clickDownload(format) {\r\n            window.open(`${this.form.download_pdf}/${format}`, \"_blank\");\r\n        },\r\n        clickSendEmail() {\r\n            this.loading = true;\r\n            this.$http\r\n                .post(`/${this.resource}/email`, {\r\n                    customer_email: this.form.customer_email,\r\n                    id: this.form.id\r\n                })\r\n                .then(response => {\r\n                    if (response.data.success) {\r\n                        this.$toast.success(\r\n                            \"El correo fue enviado satisfactoriamente\"\r\n                        );\r\n                    } else {\r\n                        this.$toast.error(\"Error al enviar el correo\");\r\n                    }\r\n                })\r\n                .catch(error => {\r\n                    if (error.response.status === 422) {\r\n                        this.errors = error.response.data.errors;\r\n                    } else {\r\n                        this.$toast.error(error.response.data.message);\r\n                    }\r\n                })\r\n                .then(() => {\r\n                    this.loading = false;\r\n                });\r\n        },\r\n        clickConsultCdr(document_id) {\r\n            this.$http\r\n                .get(`/${this.resource}/consultarcdr/${document_id}`)\r\n                .then(response => {\r\n                    if (response.data.success) {\r\n                        this.$toast.success(response.data.message);\r\n                        this.$eventHub.$emit(\"reloadData\");\r\n                    } else {\r\n                        this.$toast.error(response.data.message);\r\n                    }\r\n                })\r\n                .catch(error => {\r\n                    this.$toast.error(error.response.data.message);\r\n                });\r\n        },\r\n        clickFinalize() {\r\n            location.href = this.isContingency\r\n                ? `/contingencies`\r\n                : `/${this.resource}`;\r\n        },\r\n        clickNewDocument() {\r\n            this.clickClose();\r\n        },\r\n        clickClose() {\r\n            this.$emit(\"update:showDialog\", false);\r\n            if (this.editDocument == true) {\r\n                location.href = `/${this.resource}`;\r\n            }\r\n            this.initForm();\r\n        }\r\n    }\r\n};\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// resources/js/views/documents/partials/options.vue","<template>\r\n    <div>\r\n        <div class=\"container-fluid p-l-0 p-r-0\">\r\n            <div class=\"page-header\">\r\n                <div class=\"row\">\r\n                    <div class=\"col-sm-6\">\r\n                        <h6><span>Cotizaciones</span></h6>\r\n                        <ol class=\"breadcrumb\">\r\n                            <li class=\"breadcrumb-item\">\r\n                                <a href=\"/dashboard\">Dashboard</a>\r\n                            </li>\r\n                            <li class=\"breadcrumb-item active\">\r\n                                <span class=\"text-muted\">Cotizaciones</span>\r\n                            </li>\r\n                        </ol>\r\n                    </div>\r\n                    <div\r\n                        class=\"col-12 col-md-6 d-flex align-items-start justify-content-end\"\r\n                    >\r\n                        <a\r\n                            :href=\"`/${resource}/create`\"\r\n                            class=\"btn btn-outline-primary btn-icon btn-icon-start w-100 w-md-auto\"\r\n                        >\r\n                            <i class=\"icofont-plus-circle\"></i>\r\n                            <span>Nuevo</span>\r\n                        </a>\r\n                    </div>\r\n                </div>\r\n            </div>\r\n        </div>\r\n        <div class=\"container-fluid p-l-0 p-r-0\">\r\n            <div class=\"card mb-0\">\r\n                <div class=\"data-table-visible-columns\">\r\n                    <el-dropdown :hide-on-click=\"false\">\r\n                        <el-button type=\"primary\">\r\n                            Mostrar/Ocultar columnas<i\r\n                                class=\"el-icon-arrow-down el-icon--right\"\r\n                            ></i>\r\n                        </el-button>\r\n                        <el-dropdown-menu slot=\"dropdown\">\r\n                            <el-dropdown-item\r\n                                v-for=\"(column, index) in columns\"\r\n                                :key=\"index\"\r\n                            >\r\n                                <el-checkbox v-model=\"column.visible\">{{\r\n                                    column.title\r\n                                }}</el-checkbox>\r\n                            </el-dropdown-item>\r\n                        </el-dropdown-menu>\r\n                    </el-dropdown>\r\n                </div>\r\n                <div class=\"card-body\">\r\n                    <data-table :resource=\"resource\">\r\n                        <tr slot=\"heading\">\r\n                            <th>#</th>\r\n                            <th class=\"text-end\">Acciones</th>\r\n                            <th class=\"text-center\">Fecha Emisión</th>\r\n                            <th\r\n                                class=\"text-center\"\r\n                                v-if=\"columns.delivery_date.visible\"\r\n                            >\r\n                                Fecha Entrega\r\n                            </th>\r\n                            <th>Vendedor</th>\r\n                            <th>Cliente</th>\r\n                            <th>Estado</th>\r\n                            <th>Cotización</th>\r\n                            <th>Comprobantes</th>\r\n                            <th>Nota de venta</th>\r\n                            <th>Oportunidad Venta</th>\r\n                            <th v-if=\"columns.contract.visible\">Contrato</th>\r\n                            <!-- <th>Estado</th> -->\r\n                            <th class=\"text-center\">Moneda</th>\r\n                            <th\r\n                                class=\"text-end\"\r\n                                v-if=\"columns.total_exportation.visible\"\r\n                            >\r\n                                T.Exportación\r\n                            </th>\r\n                            <th\r\n                                class=\"text-end\"\r\n                                v-if=\"columns.total_free.visible\"\r\n                            >\r\n                                T.Gratuito\r\n                            </th>\r\n                            <th\r\n                                class=\"text-end\"\r\n                                v-if=\"columns.total_unaffected.visible\"\r\n                            >\r\n                                T.Inafecta\r\n                            </th>\r\n                            <th\r\n                                class=\"text-end\"\r\n                                v-if=\"columns.total_exonerated.visible\"\r\n                            >\r\n                                T.Exonerado\r\n                            </th>\r\n                            <th class=\"text-end\">T.Gravado</th>\r\n                            <th class=\"text-end\">T.Igv</th>\r\n                            <th class=\"text-end\">Total</th>\r\n                            <th class=\"text-center\">PDF</th>\r\n                        </tr>\r\n\r\n                        <tr></tr>\r\n                        <tr\r\n                            slot-scope=\"{ index, row }\"\r\n                            :class=\"{\r\n                                anulate_color: row.state_type_id == '11'\r\n                            }\"\r\n                        >\r\n                            <td>{{ index }}</td>\r\n\r\n                            <td class=\"text-end\">\r\n                                <div class=\"d-flex flex-wrap\">\r\n                                      <button\r\n                            \r\n                                    v-if=\"\r\n                                        row.state_type_id != '11' &&\r\n                                            row.btn_generate &&\r\n                                            (typeUser == 'admin' ||\r\n                                                typeUser == 'superadmin') &&\r\n                                            soapCompany != '03'\r\n                                    \"\r\n                                    type=\"button\"\r\n                                    class=\"m-1 btn waves-effect waves-light btn-sm btn-info\"\r\n                                    @click.prevent=\"clickOptions(row.id)\"\r\n                                >\r\n                                    Generar comprobante\r\n                                </button>\r\n\r\n                                <a\r\n                                    v-if=\"\r\n                                        row.documents.length == 0 &&\r\n                                            row.state_type_id != '11'\r\n                                    \"\r\n                                    :href=\"`/${resource}/edit/${row.id}`\"\r\n                                    type=\"button\"\r\n                                    class=\"m-1 btn waves-effect waves-light  btn-sm btn-info\"\r\n                                    >Editar</a\r\n                                >\r\n                                <button\r\n                                    v-if=\"\r\n                                        row.documents.length == 0 &&\r\n                                            row.state_type_id != '11'\r\n                                    \"\r\n                                    type=\"button\"\r\n                                    class=\"m-1 btn waves-effect waves-light btn-sm btn-danger\"\r\n                                    @click.prevent=\"clickAnulate(row.id)\"\r\n                                >\r\n                                    Anular\r\n                                </button>\r\n                                <button\r\n                                    @click=\"duplicate(row.id)\"\r\n                                    type=\"button\"\r\n                                    class=\"m-1 btn waves-effect waves-light btn-sm btn-info\"\r\n                                >\r\n                                    Duplicar\r\n                                </button>\r\n                                <a\r\n                                    v-if=\"\r\n                                        row.btn_generate_cnt &&\r\n                                            row.state_type_id != '11'\r\n                                    \"\r\n                                    :href=\"\r\n                                        `/contracts/generate-quotation/${row.id}`\r\n                                    \"\r\n                                    class=\"m-1 btn waves-effect waves-light btn-sm btn-primary m-1__2\"\r\n                                    >Generar contrato</a\r\n                                >\r\n                                </div>\r\n                            </td>\r\n                            <td class=\"text-center\">{{ row.date_of_issue }}</td>\r\n                            <td\r\n                                class=\"text-center\"\r\n                                v-if=\"columns.delivery_date.visible\"\r\n                            >\r\n                                {{ row.delivery_date }}\r\n                            </td>\r\n                            <td>{{ row.user_name }}</td>\r\n                            <td>\r\n                                {{ row.customer_name }}<br /><small\r\n                                    v-text=\"row.customer_number\"\r\n                                ></small>\r\n                            </td>\r\n                            <td>\r\n                                <template v-if=\"row.state_type_id == '11'\">\r\n                                    {{ row.state_type_description }}\r\n                                </template>\r\n                                <template v-else>\r\n                                    <el-select\r\n                                        v-model=\"row.state_type_id\"\r\n                                        @change=\"changeStateType(row)\"\r\n                                        style=\"width:120px !important\"\r\n                                    >\r\n                                        <el-option\r\n                                            v-for=\"option in state_types\"\r\n                                            :key=\"option.id\"\r\n                                            :value=\"option.id\"\r\n                                            :label=\"option.description\"\r\n                                        ></el-option>\r\n                                    </el-select>\r\n                                </template>\r\n                            </td>\r\n                            <td>{{ row.identifier }}</td>\r\n                            <td>\r\n                                <template\r\n                                    v-for=\"(document, i) in row.documents\"\r\n                                >\r\n                                    <label\r\n                                        :key=\"i\"\r\n                                        v-text=\"document.number_full\"\r\n                                        class=\"d-block\"\r\n                                    ></label>\r\n                                </template>\r\n                            </td>\r\n                            <td>\r\n                                <template\r\n                                    v-for=\"(sale_note, i) in row.sale_notes\"\r\n                                >\r\n                                    <label\r\n                                        :key=\"i\"\r\n                                        v-text=\"sale_note.identifier\"\r\n                                        class=\"d-block\"\r\n                                    ></label>\r\n                                </template>\r\n                            </td>\r\n                            <td>\r\n                                <!-- {{ row.sale_opportunity_number_full }} -->\r\n\r\n                                <el-popover\r\n                                    placement=\"right\"\r\n                                    v-if=\"row.sale_opportunity\"\r\n                                    width=\"400\"\r\n                                    trigger=\"click\"\r\n                                >\r\n                                    <div class=\"col-md-12 mt-4\">\r\n                                        <table>\r\n                                            <tr>\r\n                                                <td>\r\n                                                    <strong>O. Venta: </strong>\r\n                                                </td>\r\n                                                <td>\r\n                                                    <strong>{{\r\n                                                        row.sale_opportunity_number_full\r\n                                                    }}</strong>\r\n                                                </td>\r\n                                            </tr>\r\n                                            <tr class=\"mt-4 mb-4\">\r\n                                                <td>\r\n                                                    <strong>F. Emisión:</strong>\r\n                                                </td>\r\n                                                <td>\r\n                                                    <strong>{{\r\n                                                        row.date_of_issue\r\n                                                    }}</strong>\r\n                                                </td>\r\n                                            </tr>\r\n                                        </table>\r\n\r\n                                        <div class=\"table-responsive mt-4\">\r\n                                            <table class=\"table\">\r\n                                                <thead>\r\n                                                    <tr>\r\n                                                        <th>#</th>\r\n                                                        <th>Descripción</th>\r\n                                                        <th>Cantidad</th>\r\n                                                        <th>Total</th>\r\n                                                    </tr>\r\n                                                </thead>\r\n                                                <tbody>\r\n                                                    <tr\r\n                                                        v-for=\"(row,\r\n                                                        index) in row\r\n                                                            .sale_opportunity\r\n                                                            .items\"\r\n                                                        :key=\"index\"\r\n                                                    >\r\n                                                        <td>{{ index + 1 }}</td>\r\n                                                        <td>\r\n                                                            {{\r\n                                                                row.item\r\n                                                                    .description\r\n                                                            }}\r\n                                                        </td>\r\n                                                        <td>\r\n                                                            {{ row.quantity }}\r\n                                                        </td>\r\n                                                        <td>{{ row.total }}</td>\r\n                                                    </tr>\r\n                                                </tbody>\r\n                                            </table>\r\n                                        </div>\r\n                                    </div>\r\n                                    <el-button slot=\"reference\">\r\n                                        <i class=\"fa fa-eye\"></i\r\n                                    ></el-button>\r\n                                </el-popover>\r\n                            </td>\r\n                            <!-- <td>{{ row.state_type_description }}</td> -->\r\n                            <td v-if=\"columns.contract.visible\">\r\n                                {{ row.contract_number_full }}\r\n                            </td>\r\n                            <td class=\"text-center\">\r\n                                {{ row.currency_type_id }}\r\n                            </td>\r\n                            <td\r\n                                class=\"text-end\"\r\n                                v-if=\"columns.total_exportation.visible\"\r\n                            >\r\n                                {{ row.total_exportation }}\r\n                            </td>\r\n                            <td\r\n                                class=\"text-end\"\r\n                                v-if=\"columns.total_free.visible\"\r\n                            >\r\n                                {{ row.total_free }}\r\n                            </td>\r\n                            <td\r\n                                class=\"text-end\"\r\n                                v-if=\"columns.total_unaffected.visible\"\r\n                            >\r\n                                {{ row.total_unaffected }}\r\n                            </td>\r\n                            <td\r\n                                class=\"text-end\"\r\n                                v-if=\"columns.total_exonerated.visible\"\r\n                            >\r\n                                {{ row.total_exonerated }}\r\n                            </td>\r\n                            <td class=\"text-end\">{{ row.total_taxed }}</td>\r\n                            <td class=\"text-end\">{{ row.total_igv }}</td>\r\n                            <td class=\"text-end\">{{ row.total }}</td>\r\n                            <td class=\"text-end\">\r\n                                <button\r\n                                    type=\"button\"\r\n                                    class=\"btn waves-effect waves-light btn-xs btn-info\"\r\n                                    @click.prevent=\"clickOptionsPdf(row.id)\"\r\n                                >\r\n                                    PDF\r\n                                </button>\r\n                            </td>\r\n                        </tr>\r\n                    </data-table>\r\n                </div>\r\n\r\n                <quotation-options\r\n                    :showDialog.sync=\"showDialogOptions\"\r\n                    :recordId=\"recordId\"\r\n                    :showGenerate=\"true\"\r\n                    :showClose=\"true\"\r\n                ></quotation-options>\r\n\r\n                <quotation-options-pdf\r\n                    :showDialog.sync=\"showDialogOptionsPdf\"\r\n                    :recordId=\"recordId\"\r\n                    :showClose=\"true\"\r\n                ></quotation-options-pdf>\r\n            </div>\r\n        </div>\r\n    </div>\r\n</template>\r\n<style scoped>\r\n.anulate_color {\r\n    color: red;\r\n}\r\n</style>\r\n<script>\r\nimport QuotationOptions from \"./partials/options.vue\";\r\nimport QuotationOptionsPdf from \"./partials/options_pdf.vue\";\r\nimport DataTable from \"../../components/DataTable.vue\";\r\nimport { deletable } from \"../../mixins/deletable\";\r\n\r\nexport default {\r\n    props: [\"typeUser\", \"soapCompany\"],\r\n    mixins: [deletable],\r\n    components: { DataTable, QuotationOptions, QuotationOptionsPdf },\r\n    data() {\r\n        return {\r\n            resource: \"quotations\",\r\n            recordId: null,\r\n            showDialogOptions: false,\r\n            showDialogOptionsPdf: false,\r\n            state_types: [],\r\n            columns: {\r\n                total_exportation: {\r\n                    title: \"T.Exportación\",\r\n                    visible: false\r\n                },\r\n                total_unaffected: {\r\n                    title: \"T.Inafecto\",\r\n                    visible: false\r\n                },\r\n                total_exonerated: {\r\n                    title: \"T.Exonerado\",\r\n                    visible: false\r\n                },\r\n                total_free: {\r\n                    title: \"T.Gratuito\",\r\n                    visible: false\r\n                },\r\n                contract: {\r\n                    title: \"Contrato\",\r\n                    visible: false\r\n                },\r\n                delivery_date: {\r\n                    title: \"F.Entrega\",\r\n                    visible: false\r\n                }\r\n            }\r\n        };\r\n    },\r\n    async created() {\r\n        await this.filter();\r\n    },\r\n    methods: {\r\n        async changeStateType(row) {\r\n            await this.updateStateType(\r\n                `/${this.resource}/state-type/${row.state_type_id}/${row.id}`\r\n            ).then(() => this.$eventHub.$emit(\"reloadData\"));\r\n        },\r\n        filter() {\r\n            this.$http.get(`/${this.resource}/filter`).then(response => {\r\n                this.state_types = response.data.state_types;\r\n            });\r\n        },\r\n        clickEdit(id) {\r\n            this.recordId = id;\r\n            this.showDialogFormEdit = true;\r\n        },\r\n        clickOptions(recordId = null) {\r\n            this.recordId = recordId;\r\n            this.showDialogOptions = true;\r\n        },\r\n        clickOptionsPdf(recordId = null) {\r\n            this.recordId = recordId;\r\n            this.showDialogOptionsPdf = true;\r\n        },\r\n        clickAnulate(id) {\r\n            this.anular(`/${this.resource}/anular/${id}`).then(() =>\r\n                this.$eventHub.$emit(\"reloadData\")\r\n            );\r\n        },\r\n        duplicate(id) {\r\n            this.$http\r\n                .post(`${this.resource}/duplicate`, { id })\r\n                .then(response => {\r\n                    if (response.data.success) {\r\n                        this.$message.success(\r\n                            \"Se guardaron los cambios correctamente.\"\r\n                        );\r\n                        this.$eventHub.$emit(\"reloadData\");\r\n                    } else {\r\n                        this.$message.error(\"No se guardaron los cambios\");\r\n                    }\r\n                })\r\n                .catch(error => {});\r\n            this.$eventHub.$emit(\"reloadData\");\r\n        }\r\n    }\r\n};\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// resources/js/views/quotations/index.vue","<template>\r\n    <div>\r\n        <el-dialog\r\n            :title=\"titleDialog\"\r\n            :visible=\"showDialog\"\r\n            @open=\"create\"\r\n            @close=\"clickClose\"\r\n            width=\"650px\"\r\n            :close-on-click-modal=\"false\"\r\n            :close-on-press-escape=\"false\"\r\n            :show-close=\"false\"\r\n        >\r\n            <div class=\"row\" v-show=\"!showGenerate\">\r\n                <div\r\n                    class=\"col-lg-4 col-md-4 col-sm-4 text-center font-weight-bold\"\r\n                >\r\n                    <p>Imprimir A4</p>\r\n                    <button\r\n                        type=\"button\"\r\n                        class=\"btn btn-lg btn-info waves-effect waves-light\"\r\n                        @click=\"clickToPrint('a4')\"\r\n                    >\r\n                        <i class=\"fa fa-file-alt\"></i>\r\n                    </button>\r\n                </div>\r\n                <div\r\n                    class=\"col-lg-4 col-md-4 col-sm-4 text-center font-weight-bold\"\r\n                >\r\n                    <p>Imprimir A5</p>\r\n                    <button\r\n                        type=\"button\"\r\n                        class=\"btn btn-lg btn-info waves-effect waves-light\"\r\n                        @click=\"clickToPrint('a5')\"\r\n                    >\r\n                        <i class=\"fa fa-file-alt\"></i>\r\n                    </button>\r\n                </div>\r\n                <div\r\n                    class=\"col-lg-4 col-md-4 col-sm-4 text-center font-weight-bold\"\r\n                >\r\n                    <p>Imprimir Ticket</p>\r\n                    <button\r\n                        type=\"button\"\r\n                        class=\"btn btn-lg btn-info waves-effect waves-light\"\r\n                        @click=\"clickToPrint('ticket')\"\r\n                    >\r\n                        <i class=\"fa fa-receipt\"></i>\r\n                    </button>\r\n                </div>\r\n            </div>\r\n            <br />\r\n            <div class=\"row\" v-show=\"!showGenerate\">\r\n                <div class=\"col-md-12\">\r\n                    <el-input v-model=\"customer_email\">\r\n                        <el-button\r\n                            slot=\"append\"\r\n                            icon=\"el-icon-message\"\r\n                            @click=\"clickSendEmail\"\r\n                            :loading=\"loading\"\r\n                            >Enviar</el-button\r\n                        >\r\n                        <i slot=\"prefix\" class=\"el-icon-edit-outline\"></i\r\n                    ></el-input>\r\n                    <!--<small class=\"form-control-feedback\" v-if=\"errors.customer_email\" v-text=\"errors.customer_email[0]\"></small> -->\r\n                </div>\r\n            </div>\r\n            <br />\r\n            <div class=\"row\" v-if=\"typeUser == 'admin'\">\r\n                <div class=\"col-md-9\" v-show=\"!showGenerate\">\r\n                    <div class=\"form-group\">\r\n                        <el-checkbox v-model=\"generate\"\r\n                            >Generar comprobante electrónico</el-checkbox\r\n                        >\r\n                    </div>\r\n                </div>\r\n            </div>\r\n            <div class=\"row\" v-if=\"generate\">\r\n                <div class=\"col-lg-12 pb-2\">\r\n                    <div class=\"form-group\">\r\n                        <label\r\n                            class=\"control-label font-weight-bold text-primary\"\r\n                        >\r\n                            Cliente\r\n                            <!-- <a href=\"#\" @click.prevent=\"showDialogNewPerson = true\">[+ Nuevo]</a> -->\r\n                        </label>\r\n                        <el-select\r\n                            v-model=\"document.customer_id\"\r\n                            filterable\r\n                            remote\r\n                            class=\"border-left rounded-left border-info\"\r\n                            popper-class=\"el-select-customers\"\r\n                            dusk=\"customer_id\"\r\n                            placeholder=\"Escriba el nombre o número de documento del cliente\"\r\n                            :remote-method=\"searchRemoteCustomers\"\r\n                            @change=\"changeCustomer\"\r\n                            :loading=\"loading_search\"\r\n                        >\r\n                            <el-option\r\n                                v-for=\"option in customers\"\r\n                                :key=\"option.id\"\r\n                                :value=\"option.id\"\r\n                                :label=\"option.description\"\r\n                            ></el-option>\r\n                        </el-select>\r\n                        <small\r\n                            class=\"form-control-feedback\"\r\n                            v-if=\"errors.customer_id\"\r\n                            v-text=\"errors.customer_id[0]\"\r\n                        ></small>\r\n                    </div>\r\n                </div>\r\n\r\n                <div class=\"col-lg-8\">\r\n                    <div\r\n                        class=\"form-group\"\r\n                        :class=\"{ 'has-danger': errors.document_type_id }\"\r\n                    >\r\n                        <label class=\"control-label\">Tipo comprobante</label>\r\n                        <el-select\r\n                            v-model=\"document.document_type_id\"\r\n                            @change=\"changeDocumentType\"\r\n                            popper-class=\"el-select-document_type\"\r\n                            dusk=\"document_type_id\"\r\n                            class=\"border-left rounded-left border-info\"\r\n                        >\r\n                            <el-option\r\n                                v-for=\"option in document_types\"\r\n                                :key=\"option.id\"\r\n                                :value=\"option.id\"\r\n                                :label=\"option.description\"\r\n                            ></el-option>\r\n                            <el-option\r\n                                key=\"nv\"\r\n                                value=\"80\"\r\n                                label=\"NOTA DE VENTA\"\r\n                            ></el-option>\r\n                        </el-select>\r\n                        <small\r\n                            class=\"form-control-feedback\"\r\n                            v-if=\"errors.document_type_id\"\r\n                            v-text=\"errors.document_type_id[0]\"\r\n                        ></small>\r\n                    </div>\r\n                </div>\r\n                <div class=\"col-lg-4\">\r\n                    <div\r\n                        class=\"form-group\"\r\n                        :class=\"{ 'has-danger': errors.series_id }\"\r\n                    >\r\n                        <label class=\"control-label\">Serie</label>\r\n                        <el-select v-model=\"document.series_id\">\r\n                            <el-option\r\n                                v-for=\"option in series\"\r\n                                :key=\"option.id\"\r\n                                :value=\"option.id\"\r\n                                :label=\"option.number\"\r\n                            ></el-option>\r\n                        </el-select>\r\n                        <small\r\n                            class=\"form-control-feedback\"\r\n                            v-if=\"errors.series_id\"\r\n                            v-text=\"errors.series_id[0]\"\r\n                        ></small>\r\n                    </div>\r\n                </div>\r\n\r\n                <div class=\"col-lg-6\">\r\n                    <div\r\n                        class=\"form-group\"\r\n                        :class=\"{ 'has-danger': errors.date_of_issue }\"\r\n                    >\r\n                        <label class=\"control-label\">Fecha de emisión</label>\r\n                        <el-date-picker\r\n                            readonly\r\n                            v-model=\"document.date_of_issue\"\r\n                            type=\"date\"\r\n                            value-format=\"yyyy-MM-dd\"\r\n                            :clearable=\"false\"\r\n                            @change=\"changeDateOfIssue\"\r\n                        ></el-date-picker>\r\n                        <small\r\n                            class=\"form-control-feedback\"\r\n                            v-if=\"errors.date_of_issue\"\r\n                            v-text=\"errors.date_of_issue[0]\"\r\n                        ></small>\r\n                    </div>\r\n                </div>\r\n\r\n                <div class=\"col-lg-6\">\r\n                    <div\r\n                        class=\"form-group\"\r\n                        :class=\"{ 'has-danger': errors.date_of_issue }\"\r\n                    >\r\n                        <!--<label class=\"control-label\">Fecha de emisión</label>-->\r\n                        <label class=\"control-label\"\r\n                            >Fecha de vencimiento</label\r\n                        >\r\n                        <el-date-picker\r\n                            v-model=\"document.date_of_due\"\r\n                            type=\"date\"\r\n                            value-format=\"yyyy-MM-dd\"\r\n                            :clearable=\"false\"\r\n                        ></el-date-picker>\r\n                        <small\r\n                            class=\"form-control-feedback\"\r\n                            v-if=\"errors.date_of_due\"\r\n                            v-text=\"errors.date_of_due[0]\"\r\n                        ></small>\r\n                    </div>\r\n                </div>\r\n                <br />\r\n                <div class=\"col-lg-4\">\r\n                    <div\r\n                        class=\"form-group\"\r\n                        v-show=\"document.document_type_id == '03'\"\r\n                    >\r\n                        <el-checkbox\r\n                            v-model=\"document.is_receivable\"\r\n                            class=\"font-weight-bold\"\r\n                            >¿Es venta por cobrar?</el-checkbox\r\n                        >\r\n                    </div>\r\n                </div>\r\n                <br />\r\n                <div class=\"col-lg-12\" v-show=\"is_document_type_invoice\">\r\n                    <table>\r\n                        <thead>\r\n                            <tr width=\"100%\">\r\n                                <th v-if=\"document.payments.length > 0\">\r\n                                    M.Pago\r\n                                </th>\r\n                                <th v-if=\"document.payments.length > 0\">\r\n                                    Destino\r\n                                </th>\r\n                                <th v-if=\"document.payments.length > 0\">\r\n                                    Referencia\r\n                                </th>\r\n                                <th v-if=\"document.payments.length > 0\">\r\n                                    Monto\r\n                                </th>\r\n                                <th width=\"5%\">\r\n                                    <a\r\n                                        style=\"font-size:18px\"\r\n                                        href=\"#\"\r\n                                        @click.prevent=\"clickAddPayment\"\r\n                                        class=\"text-center font-weight-bold text-center text-info\"\r\n                                        >[+]</a\r\n                                    >\r\n                                </th>\r\n                            </tr>\r\n                        </thead>\r\n                        <tbody>\r\n                            <tr\r\n                                v-for=\"(row, index) in document.payments\"\r\n                                :key=\"index\"\r\n                            >\r\n                                <td>\r\n                                    <div class=\"form-group mb-2 mr-2\">\r\n                                        <el-select\r\n                                            v-model=\"row.payment_method_type_id\"\r\n                                        >\r\n                                            <el-option\r\n                                                v-for=\"option in payment_method_types\"\r\n                                                :key=\"option.id\"\r\n                                                :value=\"option.id\"\r\n                                                :label=\"option.description\"\r\n                                            ></el-option>\r\n                                        </el-select>\r\n                                    </div>\r\n                                </td>\r\n                                <td>\r\n                                    <div class=\"form-group mb-2 mr-2\">\r\n                                        <el-select\r\n                                            v-model=\"row.payment_destination_id\"\r\n                                            filterable\r\n                                            :disabled=\"\r\n                                                row.payment_destination_disabled\r\n                                            \"\r\n                                        >\r\n                                            <el-option\r\n                                                v-for=\"option in payment_destinations\"\r\n                                                :key=\"option.id\"\r\n                                                :value=\"option.id\"\r\n                                                :label=\"option.description\"\r\n                                            ></el-option>\r\n                                        </el-select>\r\n                                    </div>\r\n                                </td>\r\n                                <td>\r\n                                    <div class=\"form-group mb-2 mr-2\">\r\n                                        <el-input v-model=\"row.reference\">\r\n                                            <i\r\n                                                slot=\"prefix\"\r\n                                                class=\"el-icon-edit-outline\"\r\n                                            ></i\r\n                                        ></el-input>\r\n                                    </div>\r\n                                </td>\r\n                                <td>\r\n                                    <div class=\"form-group mb-2 mr-2\">\r\n                                        <el-input v-model=\"row.payment\">\r\n                                            <i\r\n                                                slot=\"prefix\"\r\n                                                class=\"el-icon-edit-outline\"\r\n                                            ></i\r\n                                        ></el-input>\r\n                                    </div>\r\n                                </td>\r\n                                <td class=\"series-table-actions text-center\">\r\n                                    <button\r\n                                        type=\"button\"\r\n                                        class=\"btn waves-effect waves-light btn-xs btn-danger\"\r\n                                        @click.prevent=\"clickCancel(index)\"\r\n                                    >\r\n                                        <i class=\"fa fa-trash\"></i>\r\n                                    </button>\r\n                                </td>\r\n                                <br />\r\n                            </tr>\r\n                        </tbody>\r\n                    </table>\r\n                </div>\r\n            </div>\r\n\r\n            <span slot=\"footer\" class=\"dialog-footer\">\r\n                <template v-if=\"showClose\">\r\n                    <el-button @click=\"clickClose\">Cerrar</el-button>\r\n                    <el-button\r\n                        class=\"submit\"\r\n                        type=\"primary\"\r\n                        @click=\"submit\"\r\n                        :loading=\"loading_submit\"\r\n                        v-if=\"generate\"\r\n                        >Generar</el-button\r\n                    >\r\n                </template>\r\n                <template v-else>\r\n                    <el-button\r\n                        class=\"submit\"\r\n                        type=\"primary\"\r\n                        plain\r\n                        @click=\"submit\"\r\n                        :loading=\"loading_submit\"\r\n                        v-if=\"generate\"\r\n                        >Generar comprobante</el-button\r\n                    >\r\n                    <el-button @click=\"clickFinalize\" v-else\r\n                        >Ir al listado</el-button\r\n                    >\r\n                    <el-button type=\"primary\" @click=\"clickNewQuotation\"\r\n                        >Nueva cotización</el-button\r\n                    >\r\n                </template>\r\n            </span>\r\n        </el-dialog>\r\n\r\n        <document-options\r\n            :showDialog.sync=\"showDialogDocumentOptions\"\r\n            :recordId=\"documentNewId\"\r\n            :isContingency=\"false\"\r\n            :showClose=\"true\"\r\n        ></document-options>\r\n\r\n        <sale-note-options\r\n            :configuration=\"configuration\"\r\n            :showDialog.sync=\"showDialogSaleNoteOptions\"\r\n            :recordId=\"documentNewId\"\r\n            :showClose=\"true\"\r\n        ></sale-note-options>\r\n    </div>\r\n</template>\r\n\r\n<script>\r\nimport DocumentOptions from \"../../documents/partials/options.vue\";\r\nimport SaleNoteOptions from \"../../sale_notes/partials/options.vue\";\r\n\r\nexport default {\r\n    components: { DocumentOptions, SaleNoteOptions },\r\n\r\n    props: [\r\n        \"showDialog\",\r\n        \"recordId\",\r\n        \"showClose\",\r\n        \"showGenerate\",\r\n        \"type\",\r\n        \"typeUser\"\r\n    ],\r\n    data() {\r\n        return {\r\n            customer_email: \"\",\r\n            titleDialog: null,\r\n            loading: false,\r\n            resource: \"quotations\",\r\n            resource_documents: \"documents\",\r\n            errors: {},\r\n            form: {},\r\n            document: {},\r\n            document_types: [],\r\n            all_document_types: [],\r\n            all_series: [],\r\n            series: [],\r\n            customers: [],\r\n            generate: false,\r\n            loading_submit: false,\r\n            showDialogDocumentOptions: false,\r\n            showDialogSaleNoteOptions: false,\r\n            documentNewId: null,\r\n            is_document_type_invoice: true,\r\n            payment_destinations: [],\r\n            loading_search: false,\r\n            payment_method_types: [],\r\n            configuration: {}\r\n        };\r\n    },\r\n    created() {\r\n        this.initForm();\r\n        this.initDocument();\r\n        this.clickAddPayment();\r\n    },\r\n    methods: {\r\n\r\n        clickCancel(index) {\r\n            this.document.payments.splice(index, 1);\r\n        },\r\n        clickAddPayment() {\r\n            this.document.payments.push({\r\n                id: null,\r\n                document_id: null,\r\n                date_of_payment: moment().format(\"YYYY-MM-DD\"),\r\n                payment_method_type_id: \"01\",\r\n                payment_destination_id: \"cash\",\r\n                reference: null,\r\n                payment: 0\r\n            });\r\n        },\r\n        initForm() {\r\n            this.generate = this.showGenerate ? true : false;\r\n            this.errors = {};\r\n            this.form = {\r\n                id: null,\r\n                external_id: null,\r\n                identifier: null,\r\n                date_of_issue: null,\r\n                quotation: null\r\n            };\r\n        },\r\n        getCustomer() {\r\n            this.$http\r\n                .get(\r\n                    `/${this.resource_documents}/search/customer/${this.form.quotation.customer_id}`\r\n                )\r\n                .then(response => {\r\n                    this.customers = response.data.customers;\r\n                    this.document.customer_id = this.form.quotation.customer_id;\r\n                    this.changeCustomer();\r\n                });\r\n        },\r\n        changeCustomer() {\r\n            this.validateIdentityDocumentType();\r\n        },\r\n        searchRemoteCustomers(input) {\r\n            if (input.length > 0) {\r\n                this.loading_search = true;\r\n                let parameters = `input=${input}&document_type_id=${this.form.document_type_id}&operation_type_id=${this.form.operation_type_id}`;\r\n\r\n                this.$http\r\n                    .get(`/${this.resource}/search/customers?${parameters}`)\r\n                    .then(response => {\r\n                        this.customers = response.data.customers;\r\n                        this.loading_search = false;\r\n                    });\r\n            }\r\n        },\r\n        initDocument() {\r\n            this.document = {\r\n                document_type_id: null,\r\n                series_id: null,\r\n                establishment_id: null,\r\n                number: \"#\",\r\n                date_of_issue: moment().format(\"YYYY-MM-DD\"),\r\n                time_of_issue: null,\r\n                customer_id: null,\r\n                currency_type_id: null,\r\n                purchase_order: null,\r\n                exchange_rate_sale: 0,\r\n                total_prepayment: 0,\r\n                total_charge: 0,\r\n                total_discount: 0,\r\n                total_exportation: 0,\r\n                total_free: 0,\r\n                total_taxed: 0,\r\n                total_unaffected: 0,\r\n                total_exonerated: 0,\r\n                total_igv: 0,\r\n                total_base_isc: 0,\r\n                total_isc: 0,\r\n                total_base_other_taxes: 0,\r\n                total_other_taxes: 0,\r\n                total_taxes: 0,\r\n                total_value: 0,\r\n                total: 0,\r\n                operation_type_id: null,\r\n                date_of_due: moment().format(\"YYYY-MM-DD\"),\r\n                items: [],\r\n                charges: [],\r\n                discounts: [],\r\n                attributes: [],\r\n                guides: [],\r\n                additional_information: null,\r\n                actions: {\r\n                    format_pdf: \"a4\"\r\n                },\r\n                quotation_id: null,\r\n                is_receivable: false,\r\n                payments: [],\r\n                hotel: {}\r\n            };\r\n        },\r\n        changeDateOfIssue() {\r\n            this.document.date_of_due = this.document.date_of_issue;\r\n        },\r\n        resetDocument() {\r\n            this.generate = this.showGenerate ? true : false;\r\n            this.initDocument();\r\n            this.document.document_type_id =\r\n                this.document_types.length > 0\r\n                    ? this.document_types[0].id\r\n                    : null;\r\n            this.changeDocumentType();\r\n        },\r\n        submit() {\r\n            this.loading_submit = true;\r\n            this.assignDocument();\r\n\r\n            if (this.document.document_type_id === \"nv\") {\r\n                this.document.prefix = \"NV\";\r\n                this.resource_documents = \"sale-notes\";\r\n            } else {\r\n                this.document.prefix = null;\r\n                this.resource_documents = \"documents\";\r\n            }\r\n\r\n            this.$http\r\n                .post(`/${this.resource_documents}`, this.document)\r\n                .then(response => {\r\n                    if (response.data.success) {\r\n                        this.documentNewId = response.data.data.id;\r\n\r\n                        this.$http\r\n                            .get(`/${this.resource}/changed/${this.form.id}`)\r\n                            .then(() => {\r\n                                this.$eventHub.$emit(\"reloadData\");\r\n                            });\r\n                        // console.log(this.document.document_type_id)\r\n                        if (this.document.document_type_id === \"nv\") {\r\n                            this.showDialogSaleNoteOptions = true;\r\n                        } else {\r\n                            this.showDialogDocumentOptions = true;\r\n                        }\r\n\r\n                        this.$eventHub.$emit(\"reloadData\");\r\n                        this.resetDocument();\r\n                        this.document.customer_id = this.form.quotation.customer_id;\r\n                        this.changeCustomer();\r\n\r\n                        this.clickClose();\r\n                    } else {\r\n                        this.$message.error(response.data.message);\r\n                    }\r\n                })\r\n                .catch(error => {\r\n                    if (error.response.status === 422) {\r\n                        this.errors = error.response.data;\r\n                    } else {\r\n                        this.$message.error(error.response.data.message);\r\n                    }\r\n                })\r\n                .then(() => {\r\n                    this.loading_submit = false;\r\n                });\r\n        },\r\n        assignDocument() {\r\n            let q = this.form.quotation;\r\n\r\n            this.document.establishment_id = q.establishment_id;\r\n            // this.document.date_of_issue = q.date_of_issue\r\n            this.document.time_of_issue = moment().format(\"HH:mm:ss\");\r\n            // this.document.customer_id = q.customer_id\r\n            this.document.currency_type_id = q.currency_type_id;\r\n            this.document.purchase_order = null;\r\n            this.document.exchange_rate_sale = q.exchange_rate_sale;\r\n            this.document.total_prepayment = q.total_prepayment;\r\n            this.document.total_charge = q.total_charge;\r\n            this.document.total_discount = q.total_discount;\r\n            this.document.total_exportation = q.total_exportation;\r\n            this.document.total_free = q.total_free;\r\n            this.document.total_taxed = q.total_taxed;\r\n            this.document.total_unaffected = q.total_unaffected;\r\n            this.document.total_exonerated = q.total_exonerated;\r\n            this.document.total_igv = q.total_igv;\r\n            this.document.total_base_isc = q.total_base_isc;\r\n            this.document.total_isc = q.total_isc;\r\n            this.document.total_base_other_taxes = q.total_base_other_taxes;\r\n            this.document.total_other_taxes = q.total_other_taxes;\r\n            this.document.total_taxes = q.total_taxes;\r\n            this.document.total_value = q.total_value;\r\n            this.document.total = q.total;\r\n            this.document.operation_type_id = \"0101\";\r\n            // this.document.date_of_due = q.date_of_issue\r\n            this.document.items = q.items;\r\n            this.document.charges = q.charges;\r\n            this.document.discounts = q.discounts;\r\n            this.document.attributes = [];\r\n            // this.document.payments = q.payments;\r\n            this.document.guides = q.guides;\r\n            this.document.additional_information = null;\r\n            this.document.actions = {\r\n                format_pdf: \"a4\"\r\n            };\r\n            this.document.quotation_id = this.form.id;\r\n        },\r\n        async create() {\r\n            await this.$http\r\n                .get(`/${this.resource}/option/tables`)\r\n                .then(response => {\r\n                    this.all_document_types =\r\n                        response.data.document_types_invoice;\r\n                    this.all_series = response.data.series;\r\n                    this.payment_destinations =\r\n                        response.data.payment_destinations;\r\n                    this.payment_method_types =\r\n                        response.data.payment_method_types;\r\n                    // this.document.document_type_id = (this.all_document_types.length > 0)?this.all_document_types[0].id:null\r\n                    // this.changeDocumentType()\r\n                });\r\n\r\n            await this.$http\r\n                .get(`/${this.resource}/record2/${this.recordId}`)\r\n                .then(response => {\r\n                    this.form = response.data.data;\r\n                    this.document.payments =\r\n                        response.data.data.quotation.payments;\r\n                    // console.log(this.form)\r\n                    // this.validateIdentityDocumentType()\r\n                    this.getCustomer();\r\n                    let type = this.type == \"edit\" ? \"editada\" : \"registrada\";\r\n                    this.titleDialog =\r\n                        `Cotización ${type}: ` + this.form.identifier;\r\n                });\r\n        },\r\n        changeDocumentType() {\r\n            // this.filterSeries()\r\n            this.document.is_receivable = false;\r\n            this.series = [];\r\n            this.filterSeries();\r\n        },\r\n        async validateIdentityDocumentType() {\r\n            let identity_document_types = [\"0\", \"1\"];\r\n            // console.log(this.document)\r\n            let customer = _.find(this.customers, {\r\n                id: this.document.customer_id\r\n            });\r\n\r\n            if (\r\n                identity_document_types.includes(\r\n                    customer.identity_document_type_id\r\n                )\r\n            ) {\r\n                this.document_types = _.filter(this.all_document_types, {\r\n                    id: \"03\"\r\n                });\r\n            } else {\r\n                this.document_types = this.all_document_types;\r\n            }\r\n\r\n            this.document.document_type_id =\r\n                this.document_types.length > 0\r\n                    ? this.document_types[0].id\r\n                    : null;\r\n            await this.changeDocumentType();\r\n        },\r\n        filterSeries() {\r\n            this.document.series_id = null;\r\n            this.series = _.filter(this.all_series, {\r\n                document_type_id: this.document.document_type_id\r\n            });\r\n            this.document.series_id =\r\n                this.series.length > 0 ? this.series[0].id : null;\r\n        },\r\n        clickFinalize() {\r\n            location.href = `/${this.resource}`;\r\n        },\r\n        clickNewQuotation() {\r\n            this.clickClose();\r\n        },\r\n        clickClose() {\r\n            this.$emit(\"update:showDialog\", false);\r\n            this.initForm();\r\n            this.resetDocument();\r\n        },\r\n        clickToPrint(format) {\r\n            window.open(\r\n                `/${this.resource}/print/${this.form.external_id}/${format}`,\r\n                \"_blank\"\r\n            );\r\n        },\r\n        clickSendEmail() {\r\n            this.loading = true;\r\n            this.$http\r\n                .post(`/${this.resource}/email`, {\r\n                    customer_email: this.customer_email,\r\n                    id: this.form.id,\r\n                    customer_id: this.form.quotation.customer_id\r\n                })\r\n                .then(response => {\r\n                    if (response.data.success) {\r\n                        this.$message.success(\r\n                            \"El correo fue enviado satisfactoriamente\"\r\n                        );\r\n                    } else {\r\n                        this.$message.error(\"Error al enviar el correo\");\r\n                    }\r\n                })\r\n                .catch(error => {\r\n                    this.$message.error(\"Error al enviar el correo\");\r\n                })\r\n                .then