"\r\n                        >\r\n                            <i class=\"fa fa-receipt\"></i>\r\n                        </button>\r\n                        <p>Imprimir Ticket</p>\r\n                    </div>\r\n                    <div\r\n                        class=\"col-lg-3 col-md-3 col-sm-12 text-center font-weight-bold mt-3\"\r\n                        v-if=\"form.view_schedule\"\r\n                    >\r\n                        <button\r\n                            type=\"button\"\r\n                            class=\"btn btn-lg btn-info waves-effect waves-light\"\r\n                            @click=\"clickPrint('cronograma')\"\r\n                        >\r\n                            <i class=\"fa fa-receipt\"></i>\r\n                        </button>\r\n                        <p>Imprimir Cronograma</p>\r\n                    </div>\r\n                </div>\r\n            </template>\r\n            <span slot=\"footer\" class=\"dialog-footer row\">\r\n                <div class=\"col-md-12\">\r\n                    <el-input v-model=\"form.customer_email\">\r\n                        <el-button\r\n                            slot=\"append\"\r\n                            icon=\"el-icon-message\"\r\n                            @click=\"clickSendEmail\"\r\n                            :loading=\"loading\"\r\n                            >Enviar</el-button\r\n                        >\r\n                        <i slot=\"prefix\" class=\"el-icon-edit-outline\"></i\r\n                    ></el-input>\r\n                </div>\r\n                <div class=\"col-md-12\" style=\"margin-top:5px;\">\r\n                    <el-input v-model=\"form.customer_telephone\">\r\n                        <el-button\r\n                            slot=\"append\"\r\n                            icon=\"fab fa-whatsapp\"\r\n                            @click=\"clickSendWhatsapp\"\r\n                            :loading=\"loading\"\r\n                            >Enviar</el-button\r\n                        >\r\n                        <i slot=\"prefix\" class=\"fab fa-whatsapp\"></i>\r\n                    </el-input>\r\n                </div>\r\n                <div class=\"col-md-12 m-t-10\">\r\n                    <template v-if=\"showClose == true\">\r\n                        <el-button @click=\"clickClose\" v-if=\"editSale == false\"\r\n                            >Cerrar</el-button\r\n                        >\r\n                        <el-button\r\n                            @click=\"clickFinalize\"\r\n                            v-if=\"editSale == true\"\r\n                            >Ir al listado</el-button\r\n                        >\r\n                    </template>\r\n                    <template v-else>\r\n                        <el-button @click=\"clickFinalize\"\r\n                            >Ir al listado</el-button\r\n                        >\r\n\r\n                        <el-button type=\"primary\" @click=\"clickNewSaleNote\"\r\n                            >Nuevo Nota de venta</el-button\r\n                        >\r\n                    </template>\r\n                </div>\r\n            </span>\r\n        </el-dialog>\r\n    </div>\r\n</template>\r\n\r\n<script>\r\nexport default {\r\n    props: [\r\n        \"showDialog\",\r\n        \"configuration\",\r\n        \"recordId\",\r\n        \"showClose\",\r\n        \"editSale\",\r\n        \"showSchedule\",\r\n        \"company\"\r\n    ],\r\n    data() {\r\n        return {\r\n            titleDialog: null,\r\n            loading: false,\r\n            resource: \"sale-notes\",\r\n            resource_documents: \"documents\",\r\n            errors: {},\r\n            form: {},\r\n            document: {},\r\n            document_types: [],\r\n            all_series: [],\r\n            series: [],\r\n            loading_submit: false,\r\n            showDialogOptions: false,\r\n            documentNewId: null,\r\n            activeName: \"first\",\r\n            sender: null\r\n        };\r\n    },\r\n    created() {\r\n        this.initForm();\r\n        this.socketWhatsappConfig();\r\n    },\r\n\r\n    methods: {\r\n        socketWhatsappConfig() {\r\n            let hostName = window.location.hostname;\r\n            let url = `https://${hostName}`;\r\n            this.sender = hostName\r\n                .replace(/https?\\:\\/\\//, \"\")\r\n                .replace(\"/\", \"\")\r\n                .split(\".\")\r\n                .join(\"\");\r\n            try {\r\n                this.socket = io.connect(this.$socketUrl);\r\n            } catch (e) {\r\n                console.log(e);\r\n            }\r\n            this.socket.on(\"ready\", message => {\r\n                this.showMessage(message);\r\n            });\r\n            this.socket.on(\"authenticated\", ({ message, sender }) => {\r\n                this.sender = sender;\r\n                this.showMessage(message);\r\n            });\r\n            this.socket.on(\"connected\", ({ message }) => {\r\n                this.$message.success(message);\r\n\r\n                this.socket.emit(\"getStatus\", url);\r\n            });\r\n            this.socket.on(\"setStatus\", ({ status, sender }) => {\r\n                if (!status) {\r\n                    this.sender = \"sdrimsac\";\r\n                    this.$message.warning(\"Sesión iniciada con SDRIMSAC\");\r\n                } else {\r\n                    this.sender = sender;\r\n                    this.$message.success(\"Whatsapp Listo!\");\r\n                }\r\n            });\r\n            //MessageResponse\r\n        },\r\n        async clickSendWhatsapp() {\r\n            if (this.form.customer_telephone != null) {\r\n                let formWhatsapp = {\r\n                    id: this.form.id,\r\n                    sender: this.sender,\r\n                    document_id: this.form.id,\r\n                    document_type_id: \"80\",\r\n                    customer_telephone: this.form.customer_telephone,\r\n                    mensaje:\r\n                        \"Su comprobante de pago electrónico \" +\r\n                        this.form.serie +\r\n                        \"-\" +\r\n                        this.form.number +\r\n                        \" de *\" +\r\n                        this.company.name +\r\n                        \"*, ha sido generado correctamente a través del facturador electrónico de *Sdrimsac Solutions*\"\r\n                };\r\n                try {\r\n                    this.loading = true;\r\n                    let response = await this.$http.post(\r\n                        `/whatsapp`,\r\n                        formWhatsapp\r\n                    );\r\n\r\n                    if (response.status == 200) {\r\n                        this.$toast.success(\"Mensaje enviado\");\r\n                        this.loading = false;\r\n                    }\r\n                } catch (e) {\r\n                    console.log(e, \" error\");\r\n                } finally {\r\n                    this.loading = false;\r\n                }\r\n            }\r\n        },\r\n        initForm() {\r\n            this.errors = {};\r\n            this.form = {\r\n                id: null,\r\n                external_id: null,\r\n                identifier: null,\r\n                date_of_issue: null,\r\n                print_ticket: null,\r\n                schedule: null,\r\n                print_a4: null,\r\n                print_a5: null,\r\n                series: null,\r\n                number: null,\r\n                view_schedule: null\r\n            };\r\n        },\r\n        async clickPrintPos(printerName, formatoPdf) {\r\n            try {\r\n                this.message =\r\n                    \"Espere imprimiendo el Comprobante \" + this.form.number;\r\n                this.loading_print = true;\r\n                let config = qz.configs.create(\r\n                    printerName,\r\n                    { scaleContent: false },\r\n                    { jobName: this.form.number }\r\n                );\r\n                if (!qz.websocket.isActive()) {\r\n                    await qz.websocket.connect(config);\r\n                }\r\n                let data = [\r\n                    {\r\n                        type: \"pdf\",\r\n                        format: \"file\",\r\n                        data: formatoPdf\r\n                    }\r\n                ];\r\n                qz.print(config, data).catch(e => {\r\n                    this.$toast.error(e.message);\r\n                });\r\n\r\n                this.loading_print = false;\r\n                this.clickClose();\r\n            } catch (e) {\r\n                this.$toast.error(e.message);\r\n            }\r\n        },\r\n        clickPrint(format) {\r\n            if (this.configuration.print_direct == 1) {\r\n                if (format == \"a4\") {\r\n                    this.clickPrintPos(this.form.printer, this.form.print_a4);\r\n                }\r\n                if (format == \"a5\") {\r\n                    this.clickPrintPos(this.form.printer, this.form.print_a5);\r\n                }\r\n                if (format == \"ticket\") {\r\n                    this.clickPrintPos(\r\n                        this.form.printer,\r\n                        this.form.print_ticket\r\n                    );\r\n                }\r\n                if (format == \"ticket_50\") {\r\n                    this.clickPrintPos(this.form.printer, this.form.ticket_50);\r\n                }\r\n                if (format == \"cronograma\") {\r\n                    this.clickPrintPos(this.form.printer, this.form.schedule);\r\n                }\r\n            }\r\n        },\r\n        async create() {\r\n            qz.security.setCertificatePromise((resolve, reject) => {\r\n                this.$http\r\n                    .get(\"/api/qz/crt/override\", {\r\n                        responseType: \"text\"\r\n                    })\r\n                    .then(response => {\r\n                        resolve(response.data);\r\n                    })\r\n                    .catch(error => {\r\n                        reject(error.data);\r\n                    });\r\n            });\r\n            qz.security.setSignaturePromise(toSign => {\r\n                return (resolve, reject) => {\r\n                    this.$http\r\n                        .post(\"/api/qz/signing\", {\r\n                            request: toSign\r\n                        })\r\n                        .then(response => {\r\n                            resolve(response.data);\r\n                        })\r\n                        .catch(error => {\r\n                            reject(error.data);\r\n                        });\r\n                };\r\n            });\r\n            await this.$http\r\n                .get(`/${this.resource}/record/${this.recordId}`)\r\n                .then(response => {\r\n                    console.log(response);\r\n                    this.form = response.data.data;\r\n                    this.titleDialog = `Nota de venta registrada:  ${this.form.serie}-${this.form.number}`;\r\n                });\r\n\r\n            // if(this.form.direct_printing==\"1\"){\r\n            //     let formatoPdf=\"\"\r\n            //     if(this.form.format_printer==\"1\"){\r\n            //          formatoPdf=this.form.print_a4\r\n            //     }else if(this.form.format_printer==\"2\"){\r\n            //            formatoPdf=this.form.print_a5\r\n            //     }else if(this.form.format_printer==\"3\"){\r\n            //            formatoPdf=this.form.print_ticket\r\n            //     }else if(this.form.format_printer==\"4\"){\r\n            //            formatoPdf=this.form.print_ticket\r\n            //     }\r\n\r\n            //     await this.clickPrintPos(this.form.printer,formatoPdf);\r\n            // }\r\n        },\r\n        clickFinalize() {\r\n            location.href = `/${this.resource}`;\r\n        },\r\n        clickNewSaleNote() {\r\n            this.clickClose();\r\n        },\r\n        clickClose() {\r\n            this.$emit(\"update:showDialog\", false);\r\n            this.$emit(\"update:showSchedule\", false);\r\n            this.initForm();\r\n        },\r\n        clickDownload() {\r\n            window.open(\r\n                `/downloads/saleNote/sale_note/${this.form.external_id}`,\r\n                \"_blank\"\r\n            );\r\n        },\r\n        clickToPrint(format) {\r\n            window.open(\r\n                `/${this.resource}/print/${this.form.id}/${format}`,\r\n                \"_blank\"\r\n            );\r\n        },\r\n        clickSendEmail() {\r\n            this.loading = true;\r\n            this.$http\r\n                .post(`/${this.resource}/email`, {\r\n                    customer_email: this.form.customer_email,\r\n                    id: this.form.id\r\n                })\r\n                .then(response => {\r\n                    if (response.data.success) {\r\n                        this.$toast.success(\r\n                            \"El correo fue enviado satisfactoriamente\"\r\n                        );\r\n                    } else {\r\n                        this.$toast.error(\"Error al enviar el correo\");\r\n                    }\r\n                })\r\n                .catch(error => {\r\n                    if (error.response.status === 422) {\r\n                        this.errors = error.response.data.errors;\r\n                    } else {\r\n                        this.$toast.error(error.response.data.message);\r\n                    }\r\n                })\r\n                .then(() => {\r\n                    this.loading = false;\r\n                });\r\n        }\r\n    }\r\n};\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// resources/js/views/sale_notes/partials/options.vue","exports = module.exports = require(\"../../../../node_modules/css-loader/lib/css-base.js\")(true);\n// imports\n\n\n// module\nexports.push([module.id, \"\\n.anulate_color[data-v-0816d5ae] {\\r\\n    color: red;\\n}\\r\\n\", \"\", {\"version\":3,\"sources\":[\"D:/laragon/www/restobar/resources/js/views/quotations/resources/js/views/quotations/index.vue\"],\"names\":[],\"mappings\":\";AA0WA;IACA,WAAA;CACA\",\"file\":\"index.vue\",\"sourcesContent\":[\"<template>\\r\\n    <div>\\r\\n        <div class=\\\"container-fluid p-l-0 p-r-0\\\">\\r\\n            <div class=\\\"page-header\\\">\\r\\n                <div class=\\\"row\\\">\\r\\n                    <div class=\\\"col-sm-6\\\">\\r\\n                        <h6><span>Cotizaciones</span></h6>\\r\\n                        <ol class=\\\"breadcrumb\\\">\\r\\n                            <li class=\\\"breadcrumb-item\\\">\\r\\n                                <a href=\\\"/dashboard\\\">Dashboard</a>\\r\\n                            </li>\\r\\n                            <li class=\\\"breadcrumb-item active\\\">\\r\\n                                <span class=\\\"text-muted\\\">Cotizaciones</span>\\r\\n                            </li>\\r\\n                        </ol>\\r\\n                    </div>\\r\\n                    <div\\r\\n                        class=\\\"col-12 col-md-6 d-flex align-items-start justify-content-end\\\"\\r\\n                    >\\r\\n                        <a\\r\\n                            :href=\\\"`/${resource}/create`\\\"\\r\\n                            class=\\\"btn btn-outline-primary btn-icon btn-icon-start w-100 w-md-auto\\\"\\r\\n                        >\\r\\n                            <i class=\\\"icofont-plus-circle\\\"></i>\\r\\n                            <span>Nuevo</span>\\r\\n                        </a>\\r\\n                    </div>\\r\\n                </div>\\r\\n            </div>\\r\\n        </div>\\r\\n        <div class=\\\"container-fluid p-l-0 p-r-0\\\">\\r\\n            <div class=\\\"card mb-0\\\">\\r\\n                <div class=\\\"data-table-visible-columns\\\">\\r\\n                    <el-dropdown :hide-on-click=\\\"false\\\">\\r\\n                        <el-button type=\\\"primary\\\">\\r\\n                            Mostrar/Ocultar columnas<i\\r\\n                                class=\\\"el-icon-arrow-down el-icon--right\\\"\\r\\n                            ></i>\\r\\n                        </el-button>\\r\\n                        <el-dropdown-menu slot=\\\"dropdown\\\">\\r\\n                            <el-dropdown-item\\r\\n                                v-for=\\\"(column, index) in columns\\\"\\r\\n                                :key=\\\"index\\\"\\r\\n                            >\\r\\n                                <el-checkbox v-model=\\\"column.visible\\\">{{\\r\\n                                    column.title\\r\\n                                }}</el-checkbox>\\r\\n                            </el-dropdown-item>\\r\\n                        </el-dropdown-menu>\\r\\n                    </el-dropdown>\\r\\n                </div>\\r\\n                <div class=\\\"card-body\\\">\\r\\n                    <data-table :resource=\\\"resource\\\">\\r\\n                        <tr slot=\\\"heading\\\">\\r\\n                            <th>#</th>\\r\\n                            <th class=\\\"text-end\\\">Acciones</th>\\r\\n                            <th class=\\\"text-center\\\">Fecha Emisión</th>\\r\\n                            <th\\r\\n                                class=\\\"text-center\\\"\\r\\n                                v-if=\\\"columns.delivery_date.visible\\\"\\r\\n                            >\\r\\n                                Fecha Entrega\\r\\n                            </th>\\r\\n                            <th>Vendedor</th>\\r\\n                            <th>Cliente</th>\\r\\n                            <th>Estado</th>\\r\\n                            <th>Cotización</th>\\r\\n                            <th>Comprobantes</th>\\r\\n                            <th>Nota de venta</th>\\r\\n                            <th>Oportunidad Venta</th>\\r\\n                            <th v-if=\\\"columns.contract.visible\\\">Contrato</th>\\r\\n                            <!-- <th>Estado</th> -->\\r\\n                            <th class=\\\"text-center\\\">Moneda</th>\\r\\n                            <th\\r\\n                                class=\\\"text-end\\\"\\r\\n                                v-if=\\\"columns.total_exportation.visible\\\"\\r\\n                            >\\r\\n                                T.Exportación\\r\\n                            </th>\\r\\n                            <th\\r\\n                                class=\\\"text-end\\\"\\r\\n                                v-if=\\\"columns.total_free.visible\\\"\\r\\n                            >\\r\\n                                T.Gratuito\\r\\n                            </th>\\r\\n                            <th\\r\\n                                class=\\\"text-end\\\"\\r\\n                                v-if=\\\"columns.total_unaffected.visible\\\"\\r\\n                            >\\r\\n                                T.Inafecta\\r\\n                            </th>\\r\\n                            <th\\r\\n                                class=\\\"text-end\\\"\\r\\n                                v-if=\\\"columns.total_exonerated.visible\\\"\\r\\n                            >\\r\\n                                T.Exonerado\\r\\n                            </th>\\r\\n                            <th class=\\\"text-end\\\">T.Gravado</th>\\r\\n                            <th class=\\\"text-end\\\">T.Igv</th>\\r\\n                            <th class=\\\"text-end\\\">Total</th>\\r\\n                            <th class=\\\"text-center\\\">PDF</th>\\r\\n                        </tr>\\r\\n\\r\\n                        <tr></tr>\\r\\n                        <tr\\r\\n                            slot-scope=\\\"{ index, row }\\\"\\r\\n                            :class=\\\"{\\r\\n                                anulate_color: row.state_type_id == '11'\\r\\n                            }\\\"\\r\\n                        >\\r\\n                            <td>{{ index }}</td>\\r\\n\\r\\n                            <td class=\\\"text-end\\\">\\r\\n                                <div class=\\\"d-flex flex-wrap\\\">\\r\\n                                      <button\\r\\n                            \\r\\n                                    v-if=\\\"\\r\\n                                        row.state_type_id != '11' &&\\r\\n                                            row.btn_generate &&\\r\\n                                            (typeUser == 'admin' ||\\r\\n                                                typeUser == 'superadmin') &&\\r\\n                                            soapCompany != '03'\\r\\n                                    \\\"\\r\\n                                    type=\\\"button\\\"\\r\\n                                    class=\\\"m-1 btn waves-effect waves-light btn-sm btn-info\\\"\\r\\n                                    @click.prevent=\\\"clickOptions(row.id)\\\"\\r\\n                                >\\r\\n                                    Generar comprobante\\r\\n                                </button>\\r\\n\\r\\n                                <a\\r\\n                                    v-if=\\\"\\r\\n                                        row.documents.length == 0 &&\\r\\n                                            row.state_type_id != '11'\\r\\n                                    \\\"\\r\\n                                    :href=\\\"`/${resource}/edit/${row.id}`\\\"\\r\\n                                    type=\\\"button\\\"\\r\\n                                    class=\\\"m-1 btn waves-effect waves-light  btn-sm btn-info\\\"\\r\\n                                    >Editar</a\\r\\n                                >\\r\\n                                <button\\r\\n                                    v-if=\\\"\\r\\n                                        row.documents.length == 0 &&\\r\\n                                            row.state_type_id != '11'\\r\\n                                    \\\"\\r\\n                                    type=\\\"button\\\"\\r\\n                                    class=\\\"m-1 btn waves-effect waves-light btn-sm btn-danger\\\"\\r\\n                                    @click.prevent=\\\"clickAnulate(row.id)\\\"\\r\\n                                >\\r\\n                                    Anular\\r\\n                                </button>\\r\\n                                <button\\r\\n                                    @click=\\\"duplicate(row.id)\\\"\\r\\n                                    type=\\\"button\\\"\\r\\n                                    class=\\\"m-1 btn waves-effect waves-light btn-sm btn-info\\\"\\r\\n                                >\\r\\n                                    Duplicar\\r\\n                                </button>\\r\\n                                <a\\r\\n                                    v-if=\\\"\\r\\n                                        row.btn_generate_cnt &&\\r\\n                                            row.state_type_id != '11'\\r\\n                                    \\\"\\r\\n                                    :href=\\\"\\r\\n                                        `/contracts/generate-quotation/${row.id}`\\r\\n                                    \\\"\\r\\n                                    class=\\\"m-1 btn waves-effect waves-light btn-sm btn-primary m-1__2\\\"\\r\\n                                    >Generar contrato</a\\r\\n                                >\\r\\n                                </div>\\r\\n                            </td>\\r\\n                            <td class=\\\"text-center\\\">{{ row.date_of_issue }}</td>\\r\\n                            <td\\r\\n                                class=\\\"text-center\\\"\\r\\n                                v-if=\\\"columns.delivery_date.visible\\\"\\r\\n                            >\\r\\n                                {{ row.delivery_date }}\\r\\n                            </td>\\r\\n                            <td>{{ row.user_name }}</td>\\r\\n                            <td>\\r\\n                                {{ row.customer_name }}<br /><small\\r\\n                                    v-text=\\\"row.customer_number\\\"\\r\\n                                ></small>\\r\\n                            </td>\\r\\n                            <td>\\r\\n                                <template v-if=\\\"row.state_type_id == '11'\\\">\\r\\n                                    {{ row.state_type_description }}\\r\\n                                </template>\\r\\n                                <template v-else>\\r\\n                                    <el-select\\r\\n                                        v-model=\\\"row.state_type_id\\\"\\r\\n                                        @change=\\\"changeStateType(row)\\\"\\r\\n                                        style=\\\"width:120px !important\\\"\\r\\n                                    >\\r\\n                                        <el-option\\r\\n                                            v-for=\\\"option in state_types\\\"\\r\\n                                            :key=\\\"option.id\\\"\\r\\n                                            :value=\\\"option.id\\\"\\r\\n                                            :label=\\\"option.description\\\"\\r\\n                                        ></el-option>\\r\\n                                    </el-select>\\r\\n                                </template>\\r\\n                            </td>\\r\\n                            <td>{{ row.identifier }}</td>\\r\\n                            <td>\\r\\n                                <template\\r\\n                                    v-for=\\\"(document, i) in row.documents\\\"\\r\\n                                >\\r\\n                                    <label\\r\\n                                        :key=\\\"i\\\"\\r\\n                                        v-text=\\\"document.number_full\\\"\\r\\n                                        class=\\\"d-block\\\"\\r\\n                                    ></label>\\r\\n                                </template>\\r\\n                            </td>\\r\\n                            <td>\\r\\n                                <template\\r\\n                                    v-for=\\\"(sale_note, i) in row.sale_notes\\\"\\r\\n                                >\\r\\n                                    <label\\r\\n                                        :key=\\\"i\\\"\\r\\n                                        v-text=\\\"sale_note.identifier\\\"\\r\\n                                        class=\\\"d-block\\\"\\r\\n                                    ></label>\\r\\n                                </template>\\r\\n                            </td>\\r\\n                            <td>\\r\\n                                <!-- {{ row.sale_opportunity_number_full }} -->\\r\\n\\r\\n                                <el-popover\\r\\n                                    placement=\\\"right\\\"\\r\\n                                    v-if=\\\"row.sale_opportunity\\\"\\r\\n                                    width=\\\"400\\\"\\r\\n                                    trigger=\\\"click\\\"\\r\\n                                >\\r\\n                                    <div class=\\\"col-md-12 mt-4\\\">\\r\\n                                        <table>\\r\\n                                            <tr>\\r\\n                                                <td>\\r\\n                                                    <strong>O. Venta: </strong>\\r\\n                                                </td>\\r\\n                                                <td>\\r\\n                